import{_ as n,o as s,c as a,a3 as t}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"97. Ohs Preliminary","description":"","frontmatter":{"title":"97. Ohs Preliminary","eba":"Nurses and Midwives 2024-2028","topics":["ohs"]},"headers":[],"relativePath":"ebas/nurses-midwives/ohs/97-ohs-preliminary.md","filePath":"ebas/nurses-midwives/ohs/97-ohs-preliminary.md"}'),r={name:"ebas/nurses-midwives/ohs/97-ohs-preliminary.md"};function o(i,e,h,l,p,d){return s(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="_97-ohs-preliminary" tabindex="-1">97. Ohs Preliminary <a class="header-anchor" href="#_97-ohs-preliminary" aria-label="Permalink to &quot;97. Ohs Preliminary&quot;">​</a></h1><p><strong>97.1</strong> Relationship to legislation</p><p>The provisions of this Part K of the Agreement will be read and interpreted in conjunction with the OHS Act, EO Act and WIRC Act and successors, provided where there is any inconsistency between this Agreement and the legislation referred to above, the legislation prevails to the extent of any inconsistency.</p><p><strong>97.2</strong> Arrangement of this Part K</p><p>This part is arranged as follows:</p><p><strong>(a)</strong> OHS Preliminary (clause 97);</p><p><strong>(b)</strong> OHS Working Group (<a href="/eba/ebas/allied-health/ohs/98-industry-ohs-working-group.html">clause 98</a>);</p><p><strong>(c)</strong> OHS Risk Management (<a href="/eba/ebas/allied-health/ohs/99-ohs-risk-management.html">clause 99</a>);</p><p><strong>(d)</strong> Incident Reporting, Investigation and Prevention (<a href="/eba/ebas/allied-health/ohs/100-incident-reporting-investigation-and-prevention.html">clause 100</a>);</p><p><strong>(e)</strong> Designated Work Groups (<a href="/eba/ebas/allied-health/ohs/101-designated-work-groups.html">clause 101</a>);</p><p><strong>(f)</strong> HSRs (<a href="/eba/ebas/allied-health/ohs/102-hsrs.html">clause 102</a>);</p><p><strong>(g)</strong> Occupational Violence and Aggression Prevention and Management (clause 103); and</p><p><strong>(h)</strong> Workers&#39; Compensation, Rehabilitation and Return To Work (<a href="/eba/ebas/nurses-midwives/ohs/104-workers-compensation-rehabilitation-and-return-to-work.html">clause 104</a>).</p><p><strong>97.3</strong> Definitions</p><p>For the purposes of this Part K of this Agreement:</p><p><strong>(a)</strong> DWG means designated work group as defined under the OHS Act as amended from time to time and may include employees other than nurses and/or midwives.</p><p><strong>(b)</strong> Incident means an event or circumstance that led or could have led to unintended or unnecessary harm.</p><p><strong>(c)</strong> Injury means any physical or mental injury.</p><p><strong>(d)</strong> Insurer means an authorised agent as defined by the WIRC Act.</p><p><strong>(e)</strong> Workplace means workplace as defined under the OHS Act.</p><p>Plain language terms: OHS overview, OHS intro.</p>',21)])])}const c=n(r,[["render",o]]);export{m as __pageData,c as default};
